/**
 * Thin wrappers around the three GDExtension interface functions needed
 * to call methods on built-in Godot objects (ClassDB method binds, singletons).
 *
 * Used by script-language infrastructure to call
 * Engine::register_script_language and friends.
 */
object ObjectCalls {

    private val globalGetSingleton by lazy {
        GodotFFI.lookup(
            "global_get_singleton",
            FunctionDescriptor.of(ADDRESS, ADDRESS),
        )
    }

    private val classdbGetMethodBind by lazy {
        GodotFFI.lookup(
            "classdb_get_method_bind",
            FunctionDescriptor.of(ADDRESS, ADDRESS, ADDRESS, JAVA_LONG),
        )
    }

    private val classdbConstructObject by lazy {
        GodotFFI.lookup(
            "classdb_construct_object2",
            FunctionDescriptor.of(ADDRESS, ADDRESS),
        )
    }

    private val objectMethodBindPtrcall by lazy {
        GodotFFI.lookup(
            "object_method_bind_ptrcall",
            FunctionDescriptor.ofVoid(ADDRESS, ADDRESS, ADDRESS, ADDRESS),
        )
    }

    private val notificationBind by lazy {
        getMethodBind("Object", "notification", 4023243586L)
    }

    private class PtrcallScratch {
        private val arena = Arena.ofAuto()
        val args1: MemorySegment = arena.allocate(ADDRESS, 1)
        val args3: MemorySegment = arena.allocate(ADDRESS, 3)
        val boolCell: MemorySegment = arena.allocate(JAVA_BYTE)
        val byteRet: MemorySegment = arena.allocate(JAVA_BYTE)
        val intRet: MemorySegment = arena.allocate(JAVA_INT)
        val longRet: MemorySegment = arena.allocate(JAVA_LONG)
        val doubleCell: MemorySegment = arena.allocate(JAVA_DOUBLE)
        val doubleRet: MemorySegment = arena.allocate(JAVA_DOUBLE)
        val objectCell: MemorySegment = arena.allocate(ADDRESS)
        val arrayRet: MemorySegment = arena.allocate(8L, 8L)
        val packedArrayRet: MemorySegment = arena.allocate(BuiltinTypes.PACKED_ARRAY_SIZE, BuiltinTypes.PACKED_ARRAY_ALIGN)
        val vector2Cell: MemorySegment = arena.allocate(GodotReal.SIZE_BYTES * 2, GodotReal.ALIGN_BYTES)
        val vector2Ret: MemorySegment = arena.allocate(GodotReal.SIZE_BYTES * 2, GodotReal.ALIGN_BYTES)
        val rect2Ret: MemorySegment = arena.allocate(GodotReal.SIZE_BYTES * 4, GodotReal.ALIGN_BYTES)
        val colorCell: MemorySegment = arena.allocate(16L, 4L)

        fun setBoolArg(value: Boolean): MemorySegment {
            boolCell.set(JAVA_BYTE, 0, if (value) 1.toByte() else 0.toByte())
            args1.setAtIndex(ADDRESS, 0, boolCell)
            return args1
        }
    }

    private val ptrcallScratch = ThreadLocal.withInitial { PtrcallScratch() }

    private fun <T> callArrayReturn(
        methodBind: MemorySegment,
        instance: MemorySegment,
        args: MemorySegment,
        reader: (MemorySegment) -> List<T>,
    ): List<T> {
        Arena.ofConfined().use { arena ->
            val ret = arena.allocate(8L, 8L)
            objectMethodBindPtrcall.invoke(methodBind, instance, args, ret)
            return try {
                reader(ret)
            } finally {
                BuiltinTypes.destroyTyped(VariantType.ARRAY, ret)
            }
        }
    }

    private fun readVariantReturn(
        methodBind: MemorySegment,
        instance: MemorySegment,
        args: MemorySegment,
        arena: Arena,
    ): Any? {
        val ret = arena.allocate(BuiltinTypes.VARIANT_SIZE, 8L)
        try {
            objectMethodBindPtrcall.invoke(methodBind, instance, args, ret)
            return BuiltinTypes.readVariantScalar(ret, arena)
        } finally {
            BuiltinTypes.destroyVariant(ret)
        }
    }

    private fun initVariantCell(arena: Arena, value: Any?): MemorySegment {
        val variant = arena.allocate(BuiltinTypes.VARIANT_SIZE, 8L)
        BuiltinTypes.initVariantFromAny(variant, value, arena)
        return variant
    }

    private val objectMethodBindCall by lazy {
        GodotFFI.lookup(
            "object_method_bind_call",
            FunctionDescriptor.ofVoid(ADDRESS, ADDRESS, ADDRESS, JAVA_LONG, ADDRESS, ADDRESS),
        )
    }

    private val objectDestroy by lazy {
        GodotFFI.lookup(
            "object_destroy",
            FunctionDescriptor.ofVoid(ADDRESS),
        )
    }

    /** Returns the Godot object pointer for a named engine singleton (e.g. "Engine"). */
    fun getSingleton(name: String): MemorySegment =
        globalGetSingleton.invoke(GodotStrings.makeStringName(name)) as MemorySegment

    /** Looks up a method bind by class name, method name, and ABI hash. Returns NULL on mismatch. */
    fun getMethodBind(className: String, methodName: String, hash: Long): MemorySegment =
        classdbGetMethodBind.invoke(
            GodotStrings.makeStringName(className),
            GodotStrings.makeStringName(methodName),
            hash,
        ) as MemorySegment

    fun constructObject(className: String): MemorySegment {
        val instance = classdbConstructObject.invoke(GodotStrings.makeStringName(className)) as MemorySegment
        // Objects created through ClassDB are not fully initialized until Godot
        // receives NOTIFICATION_POSTINITIALIZE. Theme/text controls rely on it.
        notifyPostinitialize(instance)
        return instance
    }

    fun notifyPostinitialize(instance: MemorySegment) {
        if (instance.address() == 0L) return
        ptrcallWithIntAndBoolArgs(notificationBind, instance, 0, false)
    }

    /**
     * Calls [methodBind] on [instance] via ptrcall with the given Object-typed
     * arguments. Each element of [objectArgs] is a Godot object pointer;
     * ptrcall convention requires passing a pointer-to-pointer for Object args,
     * which this function handles internally via a confined arena.
     */
    fun ptrcallWithObjectArgs(
        methodBind: MemorySegment,
        instance: MemorySegment,
        objectArgs: List<MemorySegment>,
    ) {
        Arena.ofConfined().use { arena ->
            val argsArray = if (objectArgs.isEmpty()) {
                MemorySegment.NULL
            } else {
                // For each Object* arg: allocate a cell holding the pointer,
                // then store the cell's address in the args array (double-indirect).
                val arr = arena.allocate(ADDRESS, objectArgs.size.toLong())
                objectArgs.forEachIndexed { i, obj ->
                    val cell = arena.allocate(ADDRESS)
                    cell.set(ADDRESS, 0, obj)
                    arr.setAtIndex(ADDRESS, i.toLong(), cell)
                }
                arr
            }
            objectMethodBindPtrcall.invoke(methodBind, instance, argsArray, MemorySegment.NULL)
        }
    }

    /**
     * Calls [methodBind] with one Object* arg and a bool return value.
     */
    fun ptrcallWithObjectArgRetBool(
        methodBind: MemorySegment,
        instance: MemorySegment,
        objectArg: MemorySegment,
    ): Boolean {
        Arena.ofConfined().use { arena ->
            val objCell = arena.allocate(ADDRESS)
            objCell.set(ADDRESS, 0, objectArg)
            val arr = arena.allocate(ADDRESS, 1)
            arr.setAtIndex(ADDRESS, 0, objCell)
            val ret = arena.allocate(JAVA_BYTE)
            objectMethodBindPtrcall.invoke(methodBind, instance, arr, ret)
            return ret.get(JAVA_BYTE, 0) != 0.toByte()
        }
    }

    fun ptrcallWithObjectArgRetTransform2D(
        methodBind: MemorySegment,
        instance: MemorySegment,
        objectArg: MemorySegment,
    ): Transform2D {
        Arena.ofConfined().use { arena ->
            val objCell = arena.allocate(ADDRESS)
            objCell.set(ADDRESS, 0, objectArg)
            val arr = arena.allocate(ADDRESS, 1)
            arr.setAtIndex(ADDRESS, 0, objCell)
            val ret = arena.allocate(GodotReal.SIZE_BYTES * 6, GodotReal.ALIGN_BYTES)
            objectMethodBindPtrcall.invoke(methodBind, instance, arr, ret)
            return readTransform2D(ret)
        }
    }

    /**
     * Calls [methodBind] with (Object*, String, int32) args and no return
     * value. Object args use ptrcall's pointer-to-pointer convention.
     */
    fun ptrcallWithObjectStringAndIntArgs(
        methodBind: MemorySegment,
        instance: MemorySegment,
        objectArg: MemorySegment,
        text: String,
        intArg: Int,
    ) {
        Arena.ofConfined().use { arena ->
            val objCell = arena.allocate(ADDRESS)
            val stringCell = arena.allocate(8L, 8L)
            val intCell = arena.allocate(JAVA_INT)
            try {
                objCell.set(ADDRESS, 0, objectArg)
                GodotStrings.initString(stringCell, text)
                intCell.set(JAVA_INT, 0, intArg)
                val arr = arena.allocate(ADDRESS, 3)
                arr.setAtIndex(ADDRESS, 0, objCell)
                arr.setAtIndex(ADDRESS, 1, stringCell)
                arr.setAtIndex(ADDRESS, 2, intCell)
                objectMethodBindPtrcall.invoke(methodBind, instance, arr, MemorySegment.NULL)
            } finally {
                GodotStrings.destroyString(stringCell)
            }
        }
    }

    /**
     * Calls [methodBind] with (Object*, int32, String) args and no return value.
     * Object args use ptrcall's pointer-to-pointer convention.
     */
    fun ptrcallWithObjectIntStringArgs(
        methodBind: MemorySegment,
        instance: MemorySegment,
        objectArg: MemorySegment,
        intArg: Int,
        text: String,
    ) {
        Arena.ofConfined().use { arena ->
            val objCell = arena.allocate(ADDRESS)
            val intCell = arena.allocate(JAVA_INT)
            val stringCell = arena.allocate(8L, 8L)
            try {
                objCell.set(ADDRESS, 0, objectArg)
                intCell.set(JAVA_INT, 0, intArg)
                GodotStrings.initString(stringCell, text)
                val arr = arena.allocate(ADDRESS, 3)
                arr.setAtIndex(ADDRESS, 0, objCell)
                arr.setAtIndex(ADDRESS, 1, intCell)
                arr.setAtIndex(ADDRESS, 2, stringCell)
                objectMethodBindPtrcall.invoke(methodBind, instance, arr, MemorySegment.NULL)
            } finally {
                GodotStrings.destroyString(stringCell)
            }
        }
    }

    /**
     * Calls [methodBind] with (String, bool, String) args and Object return value.
     */
    fun ptrcallWithStringBoolStringArgsRetObject(
        methodBind: MemorySegment,
        instance: MemorySegment,
        text: String,
        enabled: Boolean,
        text2: String,
    ): MemorySegment {
        Arena.ofConfined().use { arena ->
            val stringCell0 = arena.allocate(8L, 8L)
            val boolCell = arena.allocate(JAVA_BYTE)
            val stringCell2 = arena.allocate(8L, 8L)
            try {
                GodotStrings.initString(stringCell0, text)
                boolCell.set(JAVA_BYTE, 0, if (enabled) 1.toByte() else 0.toByte())
                GodotStrings.initString(stringCell2, text2)
                val arr = arena.allocate(ADDRESS, 3)
                arr.setAtIndex(ADDRESS, 0, stringCell0)
                arr.setAtIndex(ADDRESS, 1, boolCell)
                arr.setAtIndex(ADDRESS, 2, stringCell2)
                val ret = arena.allocate(ADDRESS)
                objectMethodBindPtrcall.invoke(methodBind, instance, arr, ret)
                return ret.get(ADDRESS, 0)
            } finally {
                GodotStrings.destroyString(stringCell0)
                GodotStrings.destroyString(stringCell2)
            }
        }
    }

    /**
     * Calls a vararg Object MethodBind with scalar Variant arguments and decodes
     * the scalar Variant return value.
     */
    fun callWithVariantArgs(
        methodBind: MemorySegment,
        instance: MemorySegment,
        args: List<Any?>,
    ): Any? {
        Arena.ofConfined().use { arena ->
            val variantBuffer = if (args.isEmpty()) {
                MemorySegment.NULL
            } else {
                arena.allocate(BuiltinTypes.VARIANT_SIZE * args.size, 8)
            }
            val argPtrArray = if (args.isEmpty()) {
                MemorySegment.NULL
            } else {
                arena.allocate(ADDRESS, args.size.toLong())
            }
            var initialized = 0
            val retVariant = arena.allocate(BuiltinTypes.VARIANT_SIZE, 8)
            val errStruct = arena.allocate(16L, 8L)
            var retInitialized = false

            try {
                args.forEachIndexed { i, arg ->
                    val slot = variantBuffer.asSlice(BuiltinTypes.VARIANT_SIZE * i, BuiltinTypes.VARIANT_SIZE)
                    BuiltinTypes.initVariantFromAny(slot, arg, arena)
                    initialized += 1
                    argPtrArray.setAtIndex(ADDRESS, i.toLong(), slot)
                }

                objectMethodBindCall.invoke(
                    methodBind,
                    instance,
                    argPtrArray,
                    args.size.toLong(),
                    retVariant,
                    errStruct,
                )
                retInitialized = true

                val errorType = errStruct.get(JAVA_INT, 0)
                check(errorType == 0) {
                    val argument = errStruct.get(JAVA_INT, 4)
                    val expected = errStruct.get(JAVA_INT, 8)
                    "Object.call failed: error_type=$errorType argument=$argument expected=$expected"
                }

                return BuiltinTypes.readVariantScalar(retVariant, arena)
            } finally {
                for (i in 0 until initialized) {
                    BuiltinTypes.destroyVariant(
                        variantBuffer.asSlice(BuiltinTypes.VARIANT_SIZE * i, BuiltinTypes.VARIANT_SIZE),
                    )
                }
                if (retInitialized) {
                    BuiltinTypes.destroyVariant(retVariant)
                }
            }
        }
    }

    /**
     * Calls [methodBind] via ptrcall and reads an int32 return value.
     *
     * Use this for methods whose return type is `int`/`enum Error`, e.g.
     * Engine::register_script_language and unregister_script_language.
     */
    fun ptrcallWithObjectArgsRetInt(
        methodBind: MemorySegment,
        instance: MemorySegment,
        objectArgs: List<MemorySegment>,
    ): Int {
        Arena.ofConfined().use { arena ->
            val argsArray = if (objectArgs.isEmpty()) {
                MemorySegment.NULL
            } else {
                val arr = arena.allocate(ADDRESS, objectArgs.size.toLong())
                objectArgs.forEachIndexed { i, obj ->
                    val cell = arena.allocate(ADDRESS)
                    cell.set(ADDRESS, 0, obj)
                    arr.setAtIndex(ADDRESS, i.toLong(), cell)
                }
                arr
            }
            val ret = arena.allocate(JAVA_INT)
            objectMethodBindPtrcall.invoke(methodBind, instance, argsArray, ret)
            return ret.get(JAVA_INT, 0)
        }
    }

