    fun <T : Any> ptrcallWithObjectListIntArgsRetTypedObjectList(
        methodBind: MemorySegment,
        instance: MemorySegment,
        values: List<*>,
        size: Int,
        wrapper: (MemorySegment) -> T?,
    ): List<T> =
        ptrcallWithObjectListIntArgsRetObjectList(methodBind, instance, values, size)
            .mapNotNull { wrapper(it.handle) }

