    fun ptrcallWithFourStringTwoIntBoolArgsRetPackedStringList(
        methodBind: MemorySegment,
        instance: MemorySegment,
        first: String,
        second: String,
        third: String,
        fourth: String,
        firstInt: Int,
        secondInt: Int,
        enabled: Boolean,
    ): List<String> {
        Arena.ofConfined().use { arena ->
            val firstCell = arena.allocate(8L, 8L)
            val secondCell = arena.allocate(8L, 8L)
            val thirdCell = arena.allocate(8L, 8L)
            val fourthCell = arena.allocate(8L, 8L)
            val firstIntCell = arena.allocate(JAVA_INT)
            val secondIntCell = arena.allocate(JAVA_INT)
            val boolCell = arena.allocate(JAVA_BYTE)
            val ret = BuiltinTypes.allocatePackedArray(arena)
            var firstInitialized = false
            var secondInitialized = false
            var thirdInitialized = false
            var fourthInitialized = false
            try {
                GodotStrings.initString(firstCell, first)
                firstInitialized = true
                GodotStrings.initString(secondCell, second)
                secondInitialized = true
                GodotStrings.initString(thirdCell, third)
                thirdInitialized = true
                GodotStrings.initString(fourthCell, fourth)
                fourthInitialized = true
                firstIntCell.set(JAVA_INT, 0, firstInt)
                secondIntCell.set(JAVA_INT, 0, secondInt)
                boolCell.set(JAVA_BYTE, 0, if (enabled) 1.toByte() else 0.toByte())
                val args = arena.allocate(ADDRESS, 7)
                args.setAtIndex(ADDRESS, 0, firstCell)
                args.setAtIndex(ADDRESS, 1, secondCell)
                args.setAtIndex(ADDRESS, 2, thirdCell)
                args.setAtIndex(ADDRESS, 3, fourthCell)
                args.setAtIndex(ADDRESS, 4, firstIntCell)
                args.setAtIndex(ADDRESS, 5, secondIntCell)
                args.setAtIndex(ADDRESS, 6, boolCell)
                objectMethodBindPtrcall.invoke(methodBind, instance, args, ret)
                return BuiltinTypes.readPackedStringArray(ret)
            } finally {
                BuiltinTypes.destroyTyped(VariantType.PACKED_STRING_ARRAY, ret)
                if (fourthInitialized) GodotStrings.destroyString(fourthCell)
                if (thirdInitialized) GodotStrings.destroyString(thirdCell)
                if (secondInitialized) GodotStrings.destroyString(secondCell)
                if (firstInitialized) GodotStrings.destroyString(firstCell)
            }
        }
    }

