    /**
     * Calls [methodBind] with one NodePath arg and Object return value.
     *
     * The NodePath is constructed from [path] for the duration of the ptrcall.
     */
    fun ptrcallWithNodePathArgRetObject(
        methodBind: MemorySegment,
        instance: MemorySegment,
        path: String,
    ): MemorySegment {
        Arena.ofConfined().use { arena ->
            val nodePath = arena.allocate(8L, 8L)
            val pathString = arena.allocate(8L, 8L)
            try {
                GodotStrings.initString(pathString, path)
                BuiltinTypes.construct(
                    type = VariantType.NODE_PATH,
                    dest = nodePath,
                    constructorIndex = 2,
                    args = listOf(pathString),
                )
                val arr = arena.allocate(ADDRESS, 1)
                arr.setAtIndex(ADDRESS, 0, nodePath)
                val ret = arena.allocate(ADDRESS)
                objectMethodBindPtrcall.invoke(methodBind, instance, arr, ret)
                return ret.get(ADDRESS, 0)
            } finally {
                BuiltinTypes.destroyTyped(VariantType.NODE_PATH, nodePath)
                GodotStrings.destroyString(pathString)
            }
        }
    }

