        second: Vector2i,
        third: Vector2i,
    ): List<Vector2> {
        Arena.ofConfined().use { arena ->
            val objectCell = arena.allocate(ADDRESS)
            val firstCell = arena.allocate(JAVA_INT, 2)
            val secondCell = arena.allocate(JAVA_INT, 2)
            val thirdCell = arena.allocate(JAVA_INT, 2)
            objectCell.set(ADDRESS, 0, objectArg)
            writeVector2i(firstCell, first)
            writeVector2i(secondCell, second)
