    fun ptrcallWithVector2Rect2ArgsRetBool(
        methodBind: MemorySegment,
        instance: MemorySegment,
        point: Vector2,
        rect: Rect2,
    ): Boolean {
        Arena.ofConfined().use { arena ->
            val pointCell = arena.allocate(GodotReal.SIZE_BYTES * 2, GodotReal.ALIGN_BYTES)
            val rectCell = arena.allocate(GodotReal.SIZE_BYTES * 4, GodotReal.ALIGN_BYTES)
            writeVector2(pointCell, point)
            writeRect2(rectCell, rect)
            val args = arena.allocate(ADDRESS, 2)
            args.setAtIndex(ADDRESS, 0, pointCell)
            args.setAtIndex(ADDRESS, 1, rectCell)
            val ret = arena.allocate(JAVA_BYTE)
            objectMethodBindPtrcall.invoke(methodBind, instance, args, ret)
            return ret.get(JAVA_BYTE, 0) != 0.toByte()
        }
    }

